// Validar y normalizar entrada
const body = $input.first().json.body ?? $input.first().json;

const fileName = body.file_name;
const filePath = body.file_path || body.file_name;
const content = body.content;
const version = body.version || new Date().toISOString().split('T')[0];

// Validar campos requeridos
if (!fileName) {
  throw new Error('file_name es requerido');
}

if (!content) {
  throw new Error('content es requerido');
}

// Determinar tipo de documento
let docType = 'OTHER';
const upperFileName = fileName.toUpperCase();
if (upperFileName.includes('PRD')) docType = 'PRD';
else if (upperFileName.includes('DESIGN')) docType = 'DESIGN';
else if (upperFileName.includes('TECH_STACK')) docType = 'TECH_STACK';
else if (upperFileName.includes('REGLAS') || upperFileName.includes('RULES')) docType = 'REGLAS';
else if (upperFileName.includes('CHANGELOG')) docType = 'CHANGELOG';
else if (upperFileName.includes('README')) docType = 'README';
else if (upperFileName.includes('AGENTS')) docType = 'AGENTS';

// Calcular hash del contenido para detectar cambios
const contentHash = require('crypto')
  .createHash('sha256')
  .update(content)
  .digest('hex');

return [{
  json: {
    file_name: fileName,
    file_path: filePath,
    content: content,
    content_hash: contentHash,
    version: version,
    doc_type: docType
  }
}];

// Verificar si el contenido cambió
const existing = $input.first().json;
const current = $('Validar entrada').first().json;

const hasExisting = Array.isArray(existing) && existing.length > 0;
const sameHash = hasExisting && existing[0]?.content_hash === current.content_hash;

if (hasExisting && sameHash) {
  // No hay cambios, terminar
  return [{ json: { skip: true, reason: 'content_unchanged', file_name: current.file_name } }];
}

// Devolver el registro existente si hay (para update) o null
return [{
  json: {
    skip: false,
    existing_id: hasExisting ? existing[0]?.id : null,
    ...current
  }
}];

// Preparar texto optimizado para embedding
const data = $('Filtrar si hay cambios').first().json;

// Truncar si es muy largo (Gemini tiene límites)
let content = data.content;
const maxLength = 8000; // Safe limit for embedding

if (content.length > maxLength) {
  // Tomar primero y último (mejor retención de contexto)
  const chunkSize = Math.floor(maxLength / 2);
  content = content.substring(0, chunkSize) + '\n\n...[contenido truncado]...\n\n' + content.substring(content.length - chunkSize);
}

// Crear texto enriquecido para embedding
const embedText = `[${data.doc_type}] ${data.file_name}\n\n${content}`;

return [{
  json: {
    file_name: data.file_name,
    file_path: data.file_path,
    content: data.content,
    content_hash: data.content_hash,
    version: data.version,
    doc_type: data.doc_type,
    existing_id: data.existing_id,
    embedding_text: embedText
  }
}];

// Extraer y validar embedding de Gemini
const response = $input.first().json;
const previousData = $('Preparar contenido para embedding').first().json;

const embedding = response.embedding?.values ?? [];

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error(`Gemini no devolvio embedding valido. Respuesta: ${JSON.stringify(response).slice(0, 400)}`);
}

if (embedding.length !== 768) {
  throw new Error(`Dimension incorrecta: esperadas 768, recibidas ${embedding.length}`);
}

return [{
  json: {
    ...previousData,
    embedding: embedding,
    dimensions: embedding.length
  }
}];

